 * in chained method calls. This was a regression from 0.47.1 to 0.48.x.
 *
 * See: https://github.com/pinterest/ktlint/issues/2286
 */
internal class IndentationRuleDotQualifiedSafeAccessTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a dot qualified expression followed by safe access expression in function body expression`() {
        val code =
            """
            private fun test(): Boolean? =
                runCatching { true }
                    .getOrNull()?.let { result ->
                        !result
                    }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a dot qualified expression followed by safe access expression in property`() {
        val code =
            """
            val foo = bar
                .baz()?.let { result ->
                    result + 1
                }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a safe access expression followed by dot qualified expression`() {
        val code =
            """
            val foo = bar
                ?.baz()
                .let { result ->
                    result + 1
                }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
