private fun ASTNode.isPartOfDotQualifiedAccessExpressionChain(): Boolean {
    val parentElementType = treeParent?.elementType ?: return false
    return (
        elementType == DOT_QUALIFIED_EXPRESSION ||
            elementType == SAFE_ACCESS_EXPRESSION
        ) && (
        parentElementType == DOT_QUALIFIED_EXPRESSION ||
            parentElementType == SAFE_ACCESS_EXPRESSION
        )
}

